{
  "sentences": [
    {
      "text": "你正在做什麼？",
      "pinyin": "Nǐ zhèngzài zuò shénme?",
      "pinyin_numeric": "ni3 zheng4zai4 zuo4 shen2me0",
      "translation_en": "What are you doing right now?",
      "translation_ko": "지금 무엇을 하고 계세요?"
    },
    {
      "text": "我正在看書。",
      "pinyin": "Wǒ zhèngzài kàn shū.",
      "pinyin_numeric": "wo3 zheng4zai4 kan4 shu1",
      "translation_en": "I am reading a book.",
      "translation_ko": "저는 책을 보고 있어요."
    },
    {
      "text": "他正在上網。",
      "pinyin": "Tā zhèngzài shàngwǎng.",
      "pinyin_numeric": "ta1 zheng4zai4 shang4wang3",
      "translation_en": "He is browsing the internet.",
      "translation_ko": "그는 인터넷을 하고 있어요."
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "我們正在傳訊息。",
      "pinyin": "Wǒmen zhèngzài chuán xùnxī.",
      "pinyin_numeric": "wo3men0 zheng4zai4 chuan2 xun4xi1",
      "translation_en": "We are sending messages.",
      "translation_ko": "우리는 메시지를 보내고 있어요."
    },
    {
      "text": "你正在回訊息嗎？",
      "pinyin": "Nǐ zhèngzài huí xùnxī ma?",
      "pinyin_numeric": "ni3 zheng4zai4 hui2 xun4xi1 ma0",
      "translation_en": "Are you replying to messages?",
      "translation_ko": "메시지에 답장하고 계세요?"
    },
    {
      "text": "我現在不行，正在忙。",
      "pinyin": "Wǒ xiànzài bùxíng, zhèngzài máng.",
      "pinyin_numeric": "wo3 xian4zai4 bu4xing2, zheng4zai4 mang2",
      "translation_en": "I can't right now, I'm busy.",
      "translation_ko": "지금은 안 돼요, 바쁘거든요."
    },
    {
      "text": "他正在講電話。",
      "pinyin": "Tā zhèngzài jiǎng diànhuà.",
      "pinyin_numeric": "ta1 zheng4zai4 jiang3 dian4hua4",
      "translation_en": "He is on the phone.",
      "translation_ko": "그는 전화 통화 중이에요."
    },
    {
      "text": "她正在開會。",
      "pinyin": "Tā zhèngzài kāihuì.",
      "pinyin_numeric": "ta1 zheng4zai4 kai1hui4",
      "translation_en": "She is in a meeting.",
      "translation_ko": "그녀는 회의 중이에요."
    },
    {
      "text": "你正在上課嗎？",
      "pinyin": "Nǐ zhèngzài shàngkè ma?",
      "pinyin_numeric": "ni3 zheng4zai4 shang4ke4 ma0",
      "translation_en": "Are you in class right now?",
      "translation_ko": "지금 수업 중이세요?"
    }
  ]
}
